@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page - 1))" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var pageNum in GetPageNumbers())
            {
                <li class="page-item @(pageNum == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(pageNum))">
                        @pageNum
                    </button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page + 1))" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        // Show up to 7 page buttons with ellipsis-free window around current page
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
        {
            return Enumerable.Range(1, TotalPages);
        }

        int half = maxVisible / 2;
        int start = Math.Max(1, Page - half);
        int end = start + maxVisible - 1;

        if (end > TotalPages)
        {
            end = TotalPages;
            start = end - maxVisible + 1;
        }

        return Enumerable.Range(start, end - start + 1);
    }
}

