namespace sv_d04e7cde3d5148e49b2b90572766081c.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_d04e7cde3d5148e49b2b90572766081c.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />
        </div>

        <div class="col-md-9">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (searchResult is not null && searchResult.Items.Count > 0)
            {
                <CatalogToolbar SortBy="@sortBy"
                                TotalCount="searchResult.TotalCount"
                                Page="searchResult.Page"
                                PageSize="pageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="searchResult.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination Page="searchResult.Page"
                                   TotalCount="searchResult.TotalCount"
                                   PageSize="pageSize"
                                   OnPageChanged="HandlePageChanged" />
            }
            else
            {
                <div class="text-center py-5 text-muted">
                    <h4>No products found</h4>
                    <p>Try adjusting your filters to see more results.</p>
                </div>
            }
        </div>
    </div>
}

@code {
    private List<string> categories = [];
    private PagedResult<Product>? searchResult;
    private string? errorMessage;
    private bool isLoading = true;

    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 12;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = categoriesTask.Result;
            searchResult = searchTask.Result;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            searchResult = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(CatalogFilters.ProductFilterValues values)
    {
        currentFilter = new ProductFilter(values.Categories, values.MinPrice, values.MaxPrice, values.InStockOnly);
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandleFiltersCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchProducts();
    }

    private async Task RetryLoad()
    {
        await LoadData();
    }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }
}

